+            }
+
+            fn on_stop(&mut self, cx: &Cx) -> Pin<Box<dyn Future<Output = ()> + Send + '_>> {
+                self.stop_priority
+                    .store(cx.budget().priority, Ordering::SeqCst);
+                Box::pin(async {})
+            }
+
+            fn handle_call(
+                &mut self,
+                _cx: &Cx,
+                _request: CounterCall,
+                reply: Reply<u64>,
